import { Buffer } from "node:buffer";
import fs from "node:fs";
import path from "node:path";
import { gunzipSync } from "node:zlib";
import { spawnSync } from "node:child_process";

export type PriceComparisonTemplateSeed = {
  price?: number | string | null;
  bsr?: number | string | null;
  reviewCount?: number | string | null;
  rating?: number | string | null;
  asinRevenue?: number | string | null;
};

export type PriceComparisonTemplateSlot = {
  brand: string | null;
  asin: string | null;
  link: string | null;
  comment: string | number | null;
  manualHint: boolean;
  seed?: PriceComparisonTemplateSeed;
};

export type PriceComparisonTemplateRow = {
  label: string;
  itemNumber: string | null;
  slots: PriceComparisonTemplateSlot[];
};

export type PriceComparisonTemplateCategory = {
  id: string;
  label: string;
  rows: PriceComparisonTemplateRow[];
};

const TEMPLATE_GZIP_BASE64 = "";

type CacheState = {
  key: string;
  value: PriceComparisonTemplateCategory[];
};

const rootDir = process.cwd();
const workbookPath = path.join(rootDir, "data", "price-comparison", "template.xlsx");
const jsonCachePath = path.join(rootDir, "data", "price-comparison", "template.json");
const syncScriptPath = path.join(rootDir, "scripts", "price_comparison_sync.py");

let cachedTemplate: CacheState | null = null;

function safeStat(filePath: string) {
  try {
    return fs.statSync(filePath);
  } catch {
    return null;
  }
}

function fallbackTemplate(): PriceComparisonTemplateCategory[] {
  const buffer = Buffer.from(TEMPLATE_GZIP_BASE64, "base64");
  const json = gunzipSync(buffer).toString("utf-8");
  return JSON.parse(json) as PriceComparisonTemplateCategory[];
}

function buildPythonCandidates() {
  const raw = [
    process.env.PRICE_COMPARISON_PYTHON?.trim(),
    process.env.PYTHON?.trim(),
    "/opt/homebrew/bin/python3",
    "/usr/local/bin/python3",
    "/usr/bin/python3",
    "python3",
    "python",
    "py",
  ].filter((value): value is string => Boolean(value));

  const unique = [...new Set(raw)];

  return unique.map((cmd) =>
    cmd === "py" ? { cmd, args: ["-3"] as string[] } : { cmd, args: [] as string[] }
  );
}

function runPythonScript(scriptPath: string, args: string[]) {
  const candidates = buildPythonCandidates();
  let lastError: string | null = null;

  for (const candidate of candidates) {
    if (candidate.cmd.startsWith("/") && !fs.existsSync(candidate.cmd)) {
      continue;
    }

    const result = spawnSync(candidate.cmd, [...candidate.args, scriptPath, ...args], {
      cwd: process.cwd(),
      encoding: "utf-8",
    });

    if (result.error) {
      lastError = `${candidate.cmd}: ${result.error.message}`;
      continue;
    }

    if (result.status === 0) {
      return;
    }

    lastError =
      result.stderr?.trim() ||
      result.stdout?.trim() ||
      `${candidate.cmd}: Exit code ${result.status}`;
  }

  throw new Error(
    `Excel-Export konnte nicht gestartet werden. Bitte Python + openpyxl prüfen. ${lastError ?? ""}`.trim()
  );
}
function ensureTemplateJson() {
  const workbookStat = safeStat(workbookPath);
  const jsonStat = safeStat(jsonCachePath);

  if (workbookStat) {
    const shouldSync =
      !jsonStat || workbookStat.mtimeMs > jsonStat.mtimeMs || !fs.existsSync(jsonCachePath);

    if (shouldSync) {
      fs.mkdirSync(path.dirname(jsonCachePath), { recursive: true });
      if (!fs.existsSync(syncScriptPath)) {
        throw new Error(
          "Das Template-Sync-Script fehlt. Bitte scripts/price_comparison_sync.py einfügen."
        );
      }
      runPythonScript(syncScriptPath, [workbookPath, jsonCachePath]);
    }
  }

  if (fs.existsSync(jsonCachePath)) {
    return jsonCachePath;
  }

  return null;
}

export function getTemplateWorkbookPath() {
  return fs.existsSync(workbookPath) ? workbookPath : null;
}

export function getPriceComparisonTemplate(): PriceComparisonTemplateCategory[] {
  const syncedJsonPath = ensureTemplateJson();
  const cacheKeyParts = [
    getTemplateWorkbookPath() ? String(safeStat(workbookPath)?.mtimeMs ?? 0) : "no-xlsx",
    syncedJsonPath ? String(safeStat(syncedJsonPath)?.mtimeMs ?? 0) : "no-json",
  ];
  const cacheKey = cacheKeyParts.join("|");

  if (cachedTemplate?.key === cacheKey) {
    return cachedTemplate.value;
  }

  let value: PriceComparisonTemplateCategory[];
  if (syncedJsonPath) {
    value = JSON.parse(fs.readFileSync(syncedJsonPath, "utf-8")) as PriceComparisonTemplateCategory[];
  } else {
    value = fallbackTemplate();
  }

  cachedTemplate = { key: cacheKey, value };
  return value;
}

export function getRelevantTemplateAsins(): Set<string> {
  const values = new Set<string>();
  for (const category of getPriceComparisonTemplate()) {
    for (const row of category.rows) {
      for (const slot of row.slots) {
        if (slot.asin) values.add(slot.asin);
      }
    }
  }
  return values;
}
